#include <iostream>
#include <string>

class Base
{
public:
    virtual ~Base() = default;
};

class Derived : public Base
{
public:
    std::string special() const { return "I am Derived"; }
};

int main()
{
    int n{};
    std::cin >> n;

    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;

        Base* ptr{nullptr};

        if (type == "derived")
            ptr = new Derived{};
        else
            ptr = new Base{};

        Derived* dp{dynamic_cast<Derived*>(ptr)};
        if (dp)
            std::cout << "Cast succeeded: " << dp->special() << '\n';
        else
            std::cout << "Cast failed: base object" << '\n';

        delete ptr;
    }

    return 0;
}

