solution_code:
#include <iostream>
#include <string>
#include <vector>

class Animal {
    std::string m_name;
public:
    Animal(const std::string& name) : m_name{name} {}
    virtual ~Animal() = default;
    const std::string& getName() const { return m_name; }
};

class Dog : public Animal {
public:
    Dog(const std::string& name) : Animal{name} {}
    std::string bark() const { return "Dog: " + getName() + " says Woof"; }
};

class Cat : public Animal {
public:
    Cat(const std::string& name) : Animal{name} {}
    std::string meow() const { return "Cat: " + getName() + " says Meow"; }
};

int main() {
    int n{};
    std::cin >> n;
    std::vector<Animal*> animals{};
    for (int i{0}; i < n; ++i) {
        std::string type{}, name{};
        std::cin >> type >> name;
        if (type == "dog") animals.push_back(new Dog{name});
        else animals.push_back(new Cat{name});
    }
    std::string search{};
    std::cin >> search;
    int count{0};
    for (auto* animal : animals) {
        if (search == "dog") {
            Dog* dp{dynamic_cast<Dog*>(animal)};
            if (dp) { std::cout << dp->bark() << '\n'; ++count; }
        } else {
            Cat* cp{dynamic_cast<Cat*>(animal)};
            if (cp) { std::cout << cp->meow() << '\n'; ++count; }
        }
    }
    std::cout << "Found: " << count << '\n';
    for (auto* animal : animals) delete animal;
    return 0;
}
